mapper.insert:
		/*
             SQL ID : UsrEmailAuthDAO.insert
             	설  명 : 이메일 인증 관리 등록
        */
        INSERT INTO USER_ONSLF_IDNTY (
        	  USER_ONS_VRFCTN_ID
			, USEYN
			, SENDER_NM
			, SENDER_EMAIL
			, TTL
			, SND_CTS
			, RGTR_ID
			, FRST_INQ_DTTM
			, MDFR_ID
			, MOD_DTTM
        ) VALUES (
        	  #{userEmailAuthId}
        	, #{useYn}
        	, #{senderNm}
        	, #{senderEmail}
        	, #{TTL}
        	, #{SND_CTS}
        	, #{rgtrId}
        	, FN_DTTM()
        	, #{mdfrId}
        	, FN_DTTM()
        )

mapper.update:
		/*
             SQL ID : UsrEmailAuthDAO.update
             	설  명 : 이메일 인증 관리 수정
        */
        UPDATE USER_ONSLF_IDNTY SET
        	  MDFR_ID = #{mdfrId}
        	, MOD_DTTM = FN_DTTM()

        	, USEYN = #{useYn}


        	, SENDER_NM = #{senderNm}


        	, SENDER_EMAIL = #{senderEmail}


        	, TTL = #{TTL}


        	, SND_CTS = #{SND_CTS}

         WHERE USER_ONS_VRFCTN_ID = #{userEmailAuthId}
